namespace sv_c8d339beba2046da9edaa2fb4fca80aa.Models;

public class ApplicationData
{
    public PersonalInfoData PersonalInfo { get; set; } = new();
    public ExperienceData Experience { get; set; } = new();
    public ReferencesData References { get; set; } = new();

    public bool HasPersonalInfo => !string.IsNullOrWhiteSpace(PersonalInfo.Name);
    public bool HasExperience => Experience.Jobs.Count > 0;
    public bool HasReferences => References.Contacts.Count > 0;
}

public class PersonalInfoData
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
}

public class ExperienceData
{
    public List<JobEntry> Jobs { get; set; } = [];
}

public class JobEntry
{
    public string Title { get; set; } = "";
    public string Company { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferencesData
{
    public List<ReferenceContact> Contacts { get; set; } = [];
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_c8d339beba2046da9edaa2fb4fca80aa.Models;

namespace sv_c8d339beba2046da9edaa2fb4fca80aa.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by session cookie value.
/// Both static-SSR layout and interactive-server pages run on the server,
/// so both can resolve this service and share state.
/// </summary>
public class ApplicationStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionKey)
        => _store.GetOrAdd(sessionKey, _ => new ApplicationData());

    public ApplicationData? Get(string sessionKey)
        => _store.TryGetValue(sessionKey, out var data) ? data : null;
}

namespace sv_c8d339beba2046da9edaa2fb4fca80aa.Services;

/// <summary>
/// Ensures every request has a WizardSession cookie so that
/// both static layout and interactive pages can key into the same state.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    private const string CookieName = "WizardSession";

    public WizardSessionMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionKey = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionKey, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
            // Make it available immediately for this request
            context.Items[CookieName] = sessionKey;
        }

        await _next(context);
    }

    /// <summary>
    /// Reads the session key from the cookie or from Items (first-request fallback).
    /// </summary>
    public static string GetSessionKey(HttpContext context)
    {
        if (context.Request.Cookies.TryGetValue(CookieName, out var cookie))
            return cookie;

        return context.Items[CookieName] as string ?? "";
    }
}

@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c8d339beba2046da9edaa2fb4fca80aa.Services.ApplicationStateStore StateStore

@* This layout renders statically (SSR). It reads progress from the
   server-side state store using the session cookie. *@

@{
    var uri = new Uri(Nav.Uri);
    var path = uri.AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience"    => 2,
        "/apply/references"    => 3,
        "/apply/review"        => 4,
        _                      => 0
    };

    var sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
    var data = StateStore.Get(sessionKey);
    var completedSteps = new HashSet<int>();
    if (data is not null)
    {
        if (data.HasPersonalInfo) completedSteps.Add(1);
        if (data.HasExperience) completedSteps.Add(2);
        if (data.HasReferences) completedSteps.Add(3);
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-header px-4">
            <h5 class="mb-2">Job Application — Step @currentStep of 4</h5>
            <div class="wizard-progress">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var href = step switch
                    {
                        1 => "/apply/personal-info",
                        2 => "/apply/experience",
                        3 => "/apply/references",
                        4 => "/apply/review",
                        _ => "#"
                    };
                    var label = step switch
                    {
                        1 => "Personal Info",
                        2 => "Experience",
                        3 => "References",
                        4 => "Review",
                        _ => ""
                    };
                    var css = "wizard-step";
                    if (step == currentStep) css += " active";
                    if (completedSteps.Contains(step)) css += " completed";

                    <a href="@href" class="@css">
                        <span class="step-number">@step</span>
                        <span class="step-label">@label</span>
                    </a>
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.wizard-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.wizard-progress {
    display: flex;
    gap: 0.5rem;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.75rem;
    border-radius: 1rem;
    text-decoration: none;
    font-size: 0.85rem;
    background: #e9ecef;
    color: #495057;
    transition: background 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
}

.wizard-step.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed {
    background: #198754;
    color: #fff;
}

.wizard-step.active.completed {
    background: #0d6efd;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.4rem;
    height: 1.4rem;
    border-radius: 50%;
    background: rgba(255,255,255,0.3);
    font-size: 0.75rem;
    font-weight: 700;
