using System.Collections.Concurrent;
using sv_c8d339beba2046da9edaa2fb4fca80aa.Models;

namespace sv_c8d339beba2046da9edaa2fb4fca80aa.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by session cookie value.
/// Both static-SSR layout and interactive-server pages run on the server,
/// so both can resolve this service and share state.
/// </summary>
public class ApplicationStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionKey)
        => _store.GetOrAdd(sessionKey, _ => new ApplicationData());

    public ApplicationData? Get(string sessionKey)
        => _store.TryGetValue(sessionKey, out var data) ? data : null;
}

namespace sv_c8d339beba2046da9edaa2fb4fca80aa.Services;

/// <summary>
/// Ensures every request has a WizardSession cookie so that
/// both static layout and interactive pages can key into the same state.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    private const string CookieName = "WizardSession";

    public WizardSessionMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionKey = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionKey, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
            // Make it available immediately for this request
            context.Items[CookieName] = sessionKey;
        }

        await _next(context);
    }

    /// <summary>
    /// Reads the session key from the cookie or from Items (first-request fallback).
    /// </summary>
    public static string GetSessionKey(HttpContext context)
    {
        if (context.Request.Cookies.TryGetValue(CookieName, out var cookie))
            return cookie;

        return context.Items[CookieName] as string ?? "";
    }
}

@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c8d339beba2046da9edaa2fb4fca80aa.Services.ApplicationStateStore StateStore

@* This layout renders statically (SSR). It reads progress from the
   server-side state store using the session cookie. *@

@{
    var uri = new Uri(Nav.Uri);
    var path = uri.AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience"    => 2,
        "/apply/references"    => 3,
        "/apply/review"        => 4,
        _                      => 0
    };

    var sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
    var data = StateStore.Get(sessionKey);
    var completedSteps = new HashSet<int>();
    if (data is not null)
    {
        if (data.HasPersonalInfo) completedSteps.Add(1);
        if (data.HasExperience) completedSteps.Add(2);
        if (data.HasReferences) completedSteps.Add(3);
    }
}

