@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c8d339beba2046da9edaa2fb4fca80aa.Services.ApplicationStateStore StateStore

@* This layout renders statically (SSR). It reads progress from the
   server-side state store using the session cookie. *@

@{
    var uri = new Uri(Nav.Uri);
    var path = uri.AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience"    => 2,
        "/apply/references"    => 3,
        "/apply/review"        => 4,
        _                      => 0
    };

    var sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
    var data = StateStore.Get(sessionKey);
    var completedSteps = new HashSet<int>();
    if (data is not null)
    {
        if (data.HasPersonalInfo) completedSteps.Add(1);
        if (data.HasExperience) completedSteps.Add(2);
        if (data.HasReferences) completedSteps.Add(3);
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-header px-4">
            <h5 class="mb-2">Job Application — Step @currentStep of 4</h5>
            <div class="wizard-progress">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var href = step switch
                    {
                        1 => "/apply/personal-info",
                        2 => "/apply/experience",
                        3 => "/apply/references",
                        4 => "/apply/review",
                        _ => "#"
                    };
                    var label = step switch
                    {
                        1 => "Personal Info",
                        2 => "Experience",
                        3 => "References",
                        4 => "Review",
                        _ => ""
                    };
                    var css = "wizard-step";
                    if (step == currentStep) css += " active";
                    if (completedSteps.Contains(step)) css += " completed";

                    <a href="@href" class="@css">
                        <span class="step-number">@step</span>
                        <span class="step-label">@label</span>
                    </a>
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>
"}

