@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_c8d339beba2046da9edaa2fb4fca80aa.Services.ApplicationStateStore StateStore

@* This layout renders statically (SSR). It reads progress from the
   server-side state store using the session cookie. *@

@{
    var uri = new Uri(Nav.Uri);
    var path = uri.AbsolutePath.TrimEnd('/');
    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience"    => 2,
        "/apply/references"    => 3,
        "/apply/review"        => 4,
        _                      => 0
    };

    var sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
    var data = StateStore.Get(sessionKey);
    var completedSteps = new HashSet<int>();
    if (data is not null)
    {
        if (data.HasPersonalInfo) completedSteps.Add(1);
        if (data.HasExperience) completedSteps.Add(2);
        if (data.HasReferences) completedSteps.Add(3);
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-header px-4">
            <h5 class="mb-2">Job Application — Step @currentStep of 4</h5>
            <div class="wizard-progress">
                @for (int i = 1; i <= 4; i++)
                {
                    var step = i;
                    var href = step switch
                    {
                        1 => "/apply/personal-info",
                        2 => "/apply/experience",
                        3 => "/apply/references",
                        4 => "/apply/review",
                        _ => "#"
                    };
                    var label = step switch
                    {
                        1 => "Personal Info",
                        2 => "Experience",
                        3 => "References",
                        4 => "Review",
                        _ => ""
                    };
                    var css = "wizard-step";
                    if (step == currentStep) css += " active";
                    if (completedSteps.Contains(step)) css += " completed";

                    <a href="@href" class="@css">
                        <span class="step-number">@step</span>
                        <span class="step-label">@label</span>
                    </a>
                }
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.wizard-header {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.wizard-progress {
    display: flex;
    gap: 0.5rem;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.75rem;
    border-radius: 1rem;
    text-decoration: none;
    font-size: 0.85rem;
    background: #e9ecef;
    color: #495057;
    transition: background 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
}

.wizard-step.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed {
    background: #198754;
    color: #fff;
}

.wizard-step.active.completed {
    background: #0d6efd;
}

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.4rem;
    height: 1.4rem;
    border-radius: 50%;
    background: rgba(255,255,255,0.3);
    font-size: 0.75rem;
    font-weight: 700;
}

.step-label {
    white-space: nowrap;
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .wizard-header {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .wizard-header, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

