@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout

@inject ApplicationStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Personal Info — Apply</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3" style="max-width:400px">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="Name" />
</div>

<div class="mb-3" style="max-width:400px">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private string _sessionKey = "";
    private string Name = "";
    private string Email = "";

    protected override void OnInitialized()
    {
        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionKey", _sessionKey);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionKey", out var restored))
            _sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
        else
            _sessionKey = restored ?? "";

        var data = StateStore.GetOrCreate(_sessionKey);
        Name = data.PersonalInfo.Name;
        Email = data.PersonalInfo.Email;
    }

    private void Next()
    {
        var data = StateStore.GetOrCreate(_sessionKey);
        data.PersonalInfo.Name = Name;
        data.PersonalInfo.Email = Email;
        Nav.NavigateTo("/apply/experience");
    }
}

