@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout

@inject ApplicationStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Experience — Apply</PageTitle>

<h3>Work Experience</h3>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No jobs added yet. Click "Add Job" to begin.</p>
}

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3" style="max-width:500px">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Job @(index + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <input class="form-control" @bind="_jobs[index].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="_jobs[index].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="_jobs[index].Years" />
            </div>
        </div>
    </div>
}

<div class="mb-3">
    <button class="btn btn-outline-secondary" @onclick="AddJob">+ Add Job</button>
</div>

<button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private string _sessionKey = "";
    private List<JobEntry> _jobs = [];

    protected override void OnInitialized()
    {
        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionKey", _sessionKey);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionKey", out var restored))
            _sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
        else
            _sessionKey = restored ?? "";

        var data = StateStore.GetOrCreate(_sessionKey);
        // Deep-copy so edits don't mutate the store until save
        _jobs = data.Experience.Jobs.Select(j => new JobEntry
        {
            Title = j.Title, Company = j.Company, Years = j.Years
        }).ToList();
    }

    private void AddJob() => _jobs.Add(new JobEntry());

    private void RemoveJob(int index) => _jobs.RemoveAt(index);

    private void Save()
    {
        var data = StateStore.GetOrCreate(_sessionKey);
        data.Experience.Jobs = _jobs.Select(j => new JobEntry
        {
            Title = j.Title, Company = j.Company, Years = j.Years
        }).ToList();
    }

    private void Back() { Save(); Nav.NavigateTo("/apply/personal-info"); }
    private void Next() { Save(); Nav.NavigateTo("/apply/references"); }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout

@inject ApplicationStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>References — Apply</PageTitle>

<h3>References</h3>

@if (_contacts.Count == 0)
{
    <p class="text-muted">No references added yet. Click "Add Reference" to begin.</p>
}

@for (int i = 0; i < _contacts.Count; i++)
{
    var index = i;
    <div class="card mb-3" style="max-width:500px">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Reference @(index + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveContact(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="_contacts[index].Name" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="_contacts[index].Relationship" />
            </div>
            <div class="mb-2">
                <label class="form-label">Phone</label>
                <input class="form-control" type="tel" @bind="_contacts[index].Phone" />
            </div>
        </div>
    </div>
}

<div class="mb-3">
    <button class="btn btn-outline-secondary" @onclick="AddContact">+ Add Reference</button>
</div>

<button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private string _sessionKey = "";
    private List<ReferenceContact> _contacts = [];

    protected override void OnInitialized()
    {
        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionKey", _sessionKey);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionKey", out var restored))
            _sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
        else
            _sessionKey = restored ?? "";

        var data = StateStore.GetOrCreate(_sessionKey);
        _contacts = data.References.Contacts.Select(c => new ReferenceContact
        {
            Name = c.Name, Relationship = c.Relationship, Phone = c.Phone
        }).ToList();
    }

    private void AddContact() => _contacts.Add(new ReferenceContact());

    private void RemoveContact(int index) => _contacts.RemoveAt(index);

    private void Save()
    {
        var data = StateStore.GetOrCreate(_sessionKey);
        data.References.Contacts = _contacts.Select(c => new ReferenceContact
        {
            Name = c.Name, Relationship = c.Relationship, Phone = c.Phone
        }).ToList();
    }

    private void Back() { Save(); Nav.NavigateTo("/apply/experience"); }
    private void Next() { Save(); Nav.NavigateTo("/apply/review"); }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout

@inject ApplicationStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav

<PageTitle>Review — Apply</PageTitle>

<h3>Review Your Application</h3>

@if (_data is not null)
{
    <div class="mb-4" style="max-width:600px">
        <h5>Personal Information</h5>
        <dl class="row">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@_data.PersonalInfo.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@_data.PersonalInfo.Email</dd>
        </dl>
    </div>

    <div class="mb-4" style="max-width:600px">
        <h5>Work Experience</h5>
        @if (_data.Experience.Jobs.Count == 0)
        {
            <p class="text-muted">None provided.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead>
                    <tr><th>Title</th><th>Company</th><th>Years</th></tr>
                </thead>
                <tbody>
                    @foreach (var job in _data.Experience.Jobs)
                    {
                        <tr><td>@job.Title</td><td>@job.Company</td><td>@job.Years</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>

    <div class="mb-4" style="max-width:600px">
        <h5>References</h5>
        @if (_data.References.Contacts.Count == 0)
        {
            <p class="text-muted">None provided.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead>
                    <tr><th>Name</th><th>Relationship</th><th>Phone</th></tr>
                </thead>
                <tbody>
                    @foreach (var c in _data.References.Contacts)
                    {
                        <tr><td>@c.Name</td><td>@c.Relationship</td><td>@c.Phone</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

<button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-success" @onclick="Submit">Submit Application</button>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private string _sessionKey = "";
    private ApplicationData? _data;
    private bool _submitted;

    protected override void OnInitialized()
    {
        PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionKey", _sessionKey);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionKey", out var restored))
            _sessionKey = Services.WizardSessionMiddleware.GetSessionKey(HttpContextAccessor.HttpContext!);
        else
            _sessionKey = restored ?? "";

        _data = StateStore.GetOrCreate(_sessionKey);
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        _submitted = true;
    }
}

